private void removeRelatedSettings(String apname, String path, int sheetIndex, int viewId) {
	List<RemoveSharedViewRelatedSettings> removeFuncs = new ArrayList<>();
    // Remove related reminders
    removeFuncs.add((a, p, si, seq) -> {
        try {
        	NUIForm formPage = AppManager.getFormPage(a, p, si);
            if(formPage != null) {
                formPage.removeReminderByViewId(seq);
                formPage.saveFile(a, p);
            }
        } catch(Exception e) {
            Log logger = Log.createStandardLog();
            logger.warn("Remove reminder by view failed[sheet=" + a + p + "/" + si + ", viewId=" + seq + "]");
            logger.warn(e);
        }
    });
    
    // Remove related schedule reports
    removeFuncs.add((a, p, si, seq) -> {
    	RagicAccountJobs accountJobs = RagicAccountJobs.getInstance();
        RagicAccountJobSchedule schedule = accountJobs.getJobSchedule(a, Const.JOB_EXPORT_VIEW_EMAIL);
        if(schedule == null) return;
        Set<String> paramKeysToBeRmoved = new HashSet<>();
        for(Map.Entry<String, String> e: schedule.getParamMap().entrySet()) {
            try {
                String scheduleParamKey = e.getKey();
                String paramJSONStr = e.getValue();
                JSONObject paramJSON = new JSONObject(paramJSONStr);
                
                String path_report = paramJSON.getString("path");
                if(!path_report.equals(p)) continue;
                
                String sheet_report = paramJSON.getString("sheet");
                int sheetIndex_report = Encoder.parseInt(sheet_report.substring(0, sheet_report.indexOf("_")), -1);
                if(sheetIndex_report == -1 || sheetIndex_report != si) continue;
                
                int reportId = paramJSON.getInt("reportId");
                if(reportId != seq) continue;
                
                paramKeysToBeRmoved.add(scheduleParamKey);
            } catch(Exception ignored) {
            }
        }
        
        for(String paramKeyToBeRmoved: paramKeysToBeRmoved) {
        	try {
        		   accountJobs.removeJobScheduleParam(a, Const.JOB_EXPORT_VIEW_EMAIL, paramKeyToBeRmoved);
        	} catch(Exception e) {
                Log logger = Log.createStandardLog();
                logger.warn("Remove schedule report by view failed[sheet=" + a + p + "/" + si + ", viewId=" + seq + "]");
                logger.warn(e);
            }
        }
    });
    
    removeFuncs.forEach(func -> func.remove(apname, path, sheetIndex, viewId));
}

@FunctionalInterface
private interface RemoveSharedViewRelatedSettings {
    void remove(String apname, String path, int sheetIndex, int viewId);
}

